import mockApi from './mockApi'
import { Movie, User } from '../types'

// Simple wrapper to allow switching to real fetch-based API later.
export const apiClient = {
  getMovies: async (opts?: any) => {
    return mockApi.getMovies(opts)
  },
  getMovie: async (id: string) => mockApi.getMovie(id),
  createMovie: async (payload: Omit<Movie, 'id'>) => mockApi.createMovie(payload),
  updateMovie: async (id: string, payload: Partial<Movie>) => mockApi.updateMovie(id, payload),
  deleteMovie: async (id: string) => mockApi.deleteMovie(id),
  register: async (p: { name: string; email: string; password: string }) => mockApi.register(p),
  login: async (p: { email: string; password: string }) => mockApi.login(p),
  currentUser: async () => mockApi.currentUser(),
  logout: async () => mockApi.logout(),
  toggleFavorite: async (userId: string, movieId: string) => mockApi.toggleFavorite(userId, movieId),
}

export default apiClient

import { Movie, User } from '../types'

const LS = window.localStorage
const KEY_MOVIES = 'cv_movies'
const KEY_USERS = 'cv_users'
const KEY_SESSION = 'cv_session'

function uid(prefix = '') {
  return prefix + Math.random().toString(36).slice(2, 9)
}

function hashStr(input: string) {
  // For the mock environment, use a simple deterministic encoding to simulate hashing.
  // We avoid async WebCrypto here to keep the mock synchronous and deterministic.
  try {
    return btoa(input)
  } catch (e) {
    return input
  }
}

function seedIfNeeded() {
  if (!LS.getItem(KEY_MOVIES)) {
    const sample: Movie[] = [
      { id: 'm1', title: 'The Matrix', year: 1999, type: 'movie', poster: '', description: 'A hacker discovers reality.' },
      { id: 'm2', title: 'Inception', year: 2010, type: 'movie', poster: '', description: 'Dream heist.' },
      { id: 'm3', title: 'The Office', year: 2005, type: 'series', poster: '', description: 'Workplace sitcom.' }
    ]
    LS.setItem(KEY_MOVIES, JSON.stringify(sample))
  }
  if (!LS.getItem(KEY_USERS)) {
    const adminPass = hashStr('admin123')
    const userPass = hashStr('password')
    const admin: User = { id: 'u1', name: 'Admin', email: 'admin@cv.test', password: adminPass, role: 'admin', favorites: [] }
    const user: User = { id: 'u2', name: 'Alice', email: 'alice@cv.test', password: userPass, role: 'user', favorites: ['m1'] }
    LS.setItem(KEY_USERS, JSON.stringify([admin, user]))
  }
}

// seed synchronously at module top-level so initial users are available before first calls
seedIfNeeded()

function readMovies(): Movie[] {
  return JSON.parse(LS.getItem(KEY_MOVIES) || '[]')
}
function writeMovies(movies: Movie[]) {
  LS.setItem(KEY_MOVIES, JSON.stringify(movies))
}
function readUsers(): User[] {
  return JSON.parse(LS.getItem(KEY_USERS) || '[]')
}
function writeUsers(users: User[]) {
  LS.setItem(KEY_USERS, JSON.stringify(users))
}

export const mockApi = {
  async getMovies({ q, year, type }:{ q?:string, year?:number, type?:string } = {}) {
    await delay()
    let movies = readMovies()
    if (q) {
      const qq = q.toLowerCase()
      movies = movies.filter(m => m.title.toLowerCase().includes(qq) || (m.description||'').toLowerCase().includes(qq))
    }
    if (year) movies = movies.filter(m => m.year === year)
    if (type) movies = movies.filter(m => m.type === type)
    return movies
  },
  async getMovie(id:string) {
    await delay()
    return readMovies().find(m => m.id === id) || null
  },
  async createMovie(payload: Omit<Movie, 'id'>) {
    const movies = readMovies()
    const m: Movie = { ...payload, id: uid('m') }
    movies.unshift(m)
    writeMovies(movies)
    return m
  },
  async updateMovie(id:string, payload: Partial<Movie>) {
    const movies = readMovies()
    const idx = movies.findIndex(m => m.id === id)
    if (idx === -1) throw new Error('Not found')
    movies[idx] = { ...movies[idx], ...payload }
    writeMovies(movies)
    return movies[idx]
  },
  async deleteMovie(id:string) {
    let movies = readMovies()
    movies = movies.filter(m => m.id !== id)
    writeMovies(movies)
    return true
  },
  async register({ name, email, password }:{ name:string, email:string, password:string }) {
    await delay()
    const users = readUsers()
    if (users.find(u => u.email === email)) {
      throw new Error('Email already exists')
    }
    const hashed = hashStr(password)
    const u: User = { id: uid('u'), name, email, password: hashed, role: 'user', favorites: [] }
    users.push(u)
    writeUsers(users)
    LS.setItem(KEY_SESSION, u.id)
    return u
  },
  async login({ email, password }:{ email:string, password:string }) {
    await delay()
    const users = readUsers()
    const hashed = hashStr(password)
    let u = users.find(x => x.email === email && x.password === hashed)
    if (!u) {
      // backward-compat: some users may have been stored with plaintext passwords
      const plain = users.find(x => x.email === email && x.password === password)
      if (plain) {
        // migrate to hashed password
        plain.password = hashed
        writeUsers(users)
        u = plain
      }
    }
    if (!u) throw new Error('Invalid credentials')
    LS.setItem(KEY_SESSION, u.id)
    return u
  },
  async currentUser() {
    await delay()
    const id = LS.getItem(KEY_SESSION)
    if (!id) return null
    const users = readUsers()
    return users.find(u => u.id === id) || null
  },
  async logout() {
    LS.removeItem(KEY_SESSION)
    return true
  },
  async toggleFavorite(userId:string, movieId:string) {
    const users = readUsers()
    const u = users.find(x => x.id === userId)
    if (!u) throw new Error('User not found')
    u.favorites = u.favorites || []
    if (u.favorites.includes(movieId)) {
      u.favorites = u.favorites.filter(f => f !== movieId)
    } else {
      u.favorites.push(movieId)
    }
    writeUsers(users)
    return u.favorites
  }
}

function delay(ms = 200) {
  return new Promise(resolve => setTimeout(resolve, ms))
}

export default mockApi

import React from 'react'
import { Select, Radio } from 'antd'
import { MovieType } from '../types'

export default function FilterControls({ year, setYear, type, setType }:{ year?:number, setYear:(y?:number)=>void, type?:MovieType | '', setType:(t:MovieType | '')=>void }){
  const years = Array.from({length:30}, (_,i)=> 2026 - i)
  return (
    <div style={{display:'flex',gap:12,alignItems:'center'}}>
      <Select allowClear style={{width:140}} placeholder="Year" value={year} onChange={(v)=>setYear(v)}>
        {years.map(y => <Select.Option key={y} value={y}>{y}</Select.Option>)}
      </Select>
      <Radio.Group value={type} onChange={e=>setType(e.target.value)}>
        <Radio.Button value={''}>All</Radio.Button>
        <Radio.Button value={'movie'}>Movie</Radio.Button>
        <Radio.Button value={'series'}>Series</Radio.Button>
      </Radio.Group>
    </div>
  )
}

import React from 'react'
import { Card, Button } from 'antd'
import { HeartOutlined, HeartFilled } from '@ant-design/icons'
import { Movie } from '../types'
import { useAuth } from '../hooks/useAuth'

const { Meta } = Card

export default function MovieCard({ movie, onEdit, onDelete }:{ movie:Movie, onEdit?:()=>void, onDelete?:()=>void }){
  const { user, toggleFavorite, isAdmin } = useAuth()
  const fav = user?.favorites?.includes(movie.id)
  return (
    <Card
      hoverable
      style={{ width: 240 }}
      cover={<div style={{height:320,background:'#ddd',display:'flex',alignItems:'center',justifyContent:'center'}}>{movie.poster ? <img src={movie.poster} alt={movie.title} style={{maxHeight:'100%',maxWidth:'100%'}}/> : <div style={{padding:20}}>{movie.title}</div>}</div>}
      actions={[
        <Button type="text" onClick={() => toggleFavorite(movie.id)} icon={fav ? <HeartFilled style={{color:'crimson'}}/> : <HeartOutlined />} />,
        isAdmin() ? <Button key="edit" type="link" onClick={onEdit}>Edit</Button> : null,
        isAdmin() ? <Button key="del" type="link" danger onClick={onDelete}>Delete</Button> : null
      ].filter(Boolean) as any}
    >
      <Meta title={`${movie.title} (${movie.year})`} description={movie.type} />
    </Card>
  )
}

import React, { useEffect } from 'react'
import { Modal, Form, Input, Select, InputNumber, message } from 'antd'
import { Movie } from '../types'
import { apiClient } from '../api/apiClient'

export default function MovieForm({ open, onClose, movie }:{ open:boolean, onClose:()=>void, movie:Movie | null }){
  const [form] = Form.useForm()
  useEffect(()=>{ if (movie) form.setFieldsValue(movie); else form.resetFields() }, [movie, form])

  const onFinish = async (vals:any) => {
    try{
      if (movie) await apiClient.updateMovie(movie.id, vals)
      else await apiClient.createMovie(vals)
      message.success('Saved')
      onClose()
    }catch(e:any){ message.error(e.message || 'Save failed') }
  }

  return (
    <Modal title={movie ? 'Edit Movie' : 'New Movie'} open={open} onCancel={onClose} onOk={() => form.submit()}>
      <Form form={form} layout="vertical" onFinish={onFinish} initialValues={{ type: 'movie' }}>
        <Form.Item name="title" label="Title" rules={[{required:true, message: '請輸入標題'}]}> <Input /> </Form.Item>
        <Form.Item name="year" label="Year" rules={[{required:true, message: '請輸入年份'}, { type: 'number', message: '年份必須為數字'}]}> <InputNumber style={{width:'100%'}} /> </Form.Item>
        <Form.Item name="type" label="Type" rules={[{ required: true, message: '請選擇類型' }]}>
          <Select>
            <Select.Option value="movie">Movie</Select.Option>
            <Select.Option value="series">Series</Select.Option>
          </Select>
        </Form.Item>
        <Form.Item name="poster" label="Poster URL" rules={[{ type: 'url', message: '請輸入有效的 URL 或留空' }]}>
          <Input />
        </Form.Item>
        <Form.Item name="description" label="Description"> <Input.TextArea /> </Form.Item>
      </Form>
    </Modal>
  )
}

import React from 'react'
import { Row, Col } from 'antd'
import MovieCard from './MovieCard'
import { Movie } from '../types'

export default function MovieList({ movies, onEdit, onDelete }:{ movies:Movie[], onEdit?:(m:Movie)=>void, onDelete?:(m:Movie)=>void }){
  return (
    <Row gutter={[16,16]}>
      {movies.map(m => (
        <Col key={m.id} xs={24} sm={12} md={8} lg={6}>
          <MovieCard movie={m} onEdit={() => onEdit?.(m)} onDelete={() => onDelete?.(m)} />
        </Col>
      ))}
    </Row>
  )
}

import React from 'react'
import { Input } from 'antd'

export default function SearchBar({ value, onChange }:{ value:string, onChange:(v:string)=>void }){
  return (
    <Input.Search
      placeholder="Search by title or description"
      allowClear
      value={value}
      onChange={e=>onChange(e.target.value)}
      style={{ maxWidth: 480 }}
    />
  )
}

import React, { createContext, useContext, useEffect, useState } from 'react'
import { apiClient } from '../api/apiClient'
import { User } from '../types'
import { message } from 'antd'

interface AuthContextValue {
  user: User | null
  loading: boolean
  register: (name:string,email:string,password:string)=>Promise<void>
  login: (email:string,password:string)=>Promise<void>
  logout: ()=>Promise<void>
  toggleFavorite: (movieId:string)=>Promise<void>
  isAdmin: ()=>boolean
}

const AuthContext = createContext<AuthContextValue | undefined>(undefined)

export const AuthProvider: React.FC<{ children: React.ReactNode }>= ({ children }) => {
  const [user, setUser] = useState<User | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    ;(async () => {
      try {
        const u = await apiClient.currentUser()
        setUser(u)
      } catch (e) {
        console.error(e)
      } finally {
        setLoading(false)
      }
    })()
  }, [])

  const register = async (name:string,email:string,password:string) => {
    setLoading(true)
    try {
      const u = await apiClient.register({ name, email, password })
      setUser(u)
      message.success('Registered and logged in')
    } catch (e:any) {
      message.error(e.message || 'Register failed')
      throw e
    } finally { setLoading(false) }
  }
  const login = async (email:string,password:string) => {
    setLoading(true)
    try {
      const u = await apiClient.login({ email, password })
      setUser(u)
      message.success('Welcome back')
    } catch (e:any) {
      message.error(e.message || 'Login failed')
      throw e
    } finally { setLoading(false) }
  }
  const logout = async () => {
    await apiClient.logout()
    setUser(null)
    message.info('Logged out')
  }
  const toggleFavorite = async (movieId:string) => {
    if (!user) { message.info('Please login to manage favorites'); throw new Error('Not logged in') }
    const favs = await apiClient.toggleFavorite(user.id, movieId)
    setUser({ ...user, favorites: favs })
  }
  const isAdmin = () => !!user && user.role === 'admin'

  return (
    <AuthContext.Provider value={{ user, loading, register, login, logout, toggleFavorite, isAdmin }}>
      {children}
    </AuthContext.Provider>
  )
}

export function useAuthContext() {
  const ctx = useContext(AuthContext)
  if (!ctx) throw new Error('useAuthContext must be used within AuthProvider')
  return ctx
}

@import "https://cdn.jsdelivr.net/npm/antd@5.10.0/dist/reset.css";

html, body, #root {
