import React, { useEffect, useState } from 'react'
import { useLocation, useNavigate } from 'react-router-dom'
import { Table, Button, Space, Popconfirm, message } from 'antd'
import { apiClient } from '../../api/apiClient'
import { Movie } from '../../types'
import MovieForm from '../../components/MovieForm'

export default function AdminDashboard(){
  const [movies, setMovies] = useState<Movie[]>([])
  const [loading, setLoading] = useState(false)
  const [visible, setVisible] = useState(false)
  const [editing, setEditing] = useState<Movie | null>(null)

  const load = async () => {
    setLoading(true)
    const list = await apiClient.getMovies()
    setMovies(list)
    setLoading(false)
  }
  useEffect(()=>{ load() }, [])

  // open edit modal if navigated here with state.editId
  const location = useLocation()
  useEffect(() => {
    const anyState = (location as any).state
    if (anyState && anyState.editId) {
      const movie = movies.find(m => m.id === anyState.editId)
      if (movie) {
        setEditing(movie)
        setVisible(true)
        // clear the navigation state so modal won't reopen on subsequent renders
        navigate(location.pathname, { replace: true, state: {} })
      }
    }
  }, [location, movies, navigate])

  const onDelete = async (m:Movie) => {
    await apiClient.deleteMovie(m.id)
    message.success('Deleted')
    load()
  }
  const onEdit = (m:Movie) => { setEditing(m); setVisible(true) }
  const onCreate = () => { setEditing(null); setVisible(true) }

  return (
    <div>
      <Space style={{marginBottom:16}}>
        <Button type="primary" onClick={onCreate}>New Movie</Button>
        <Button onClick={load}>Refresh</Button>
      </Space>
      <Table dataSource={movies} rowKey="id" loading={loading}>
        <Table.Column title="Title" dataIndex="title" key="title" />
        <Table.Column title="Year" dataIndex="year" key="year" />
        <Table.Column title="Type" dataIndex="type" key="type" />
        <Table.Column title="Actions" key="actions" render={(_, record:Movie) => (
          <Space>
            <Button onClick={()=>onEdit(record)}>Edit</Button>
            <Popconfirm title="Delete?" onConfirm={()=>onDelete(record)}>
              <Button danger>Delete</Button>
            </Popconfirm>
          </Space>
        )} />
      </Table>

      <MovieForm open={visible} onClose={() => { setVisible(false); load() }} movie={editing} />
    </div>
  )
}

function MovieForm({ open, onClose, movie }:{ open:boolean, onClose:()=>void, movie:Movie | null }){
  const [form] = Form.useForm()

  useEffect(()=>{ if (movie) form.setFieldsValue(movie); else form.resetFields() }, [movie])

  const onFinish = async (vals:any) => {
    try{
      if (movie) await apiClient.updateMovie(movie.id, vals)
      else await apiClient.createMovie(vals)
      message.success('Saved')
      onClose()
    }catch(e:any){ message.error(e.message || 'Save failed') }
  }

  return (
      <Modal title={movie ? 'Edit Movie' : 'New Movie'} open={open} onCancel={onClose} onOk={() => form.submit()}>
      <Form form={form} layout="vertical" onFinish={onFinish} initialValues={{ type: 'movie' }}>
        <Form.Item
          name="title"
          label="Title"
          rules={[{ required: true, message: '請輸入標題' }]}
        >
          <Input />
        </Form.Item>
        <Form.Item
          name="year"
          label="Year"
          rules={[{ required: true, message: '請輸入年份' }, { type: 'number', message: '年份必須為數字' }]}
        >
          <InputNumber style={{ width: '100%' }} />
        </Form.Item>
        <Form.Item
          name="type"
          label="Type"
          rules={[{ required: true, message: '請選擇類型' }]}
        >
          <Select>
            <Select.Option value="movie">Movie</Select.Option>
            <Select.Option value="series">Series</Select.Option>
          </Select>
        </Form.Item>
        <Form.Item
          name="poster"
          label="Poster URL"
          rules={[{ type: 'url', message: '請輸入有效的 URL 或留空' }]}
        >
          <Input />
        </Form.Item>
        <Form.Item name="description" label="Description"> <Input.TextArea /> </Form.Item>
      </Form>
    </Modal>
  )
}

import React, { useEffect, useState } from 'react'
import { useAuth } from '../hooks/useAuth'
import { apiClient } from '../api/apiClient'
import MovieList from '../components/MovieList'
import { Movie } from '../types'
import { Spin, Empty } from 'antd'

export default function Favorites(){
  const { user } = useAuth()
  const [movies, setMovies] = useState<Movie[]>([])
  const [loading, setLoading] = useState(false)

  useEffect(() => {
    if (!user) return
    setLoading(true)
    Promise.all((user.favorites||[]).map(id => apiClient.getMovie(id))).then(list => setMovies(list.filter(Boolean) as Movie[])).finally(()=>setLoading(false))
  }, [user])

  if (!user) return <div>Please login to see favorites</div>
  return (
    <div>
      {loading ? <Spin /> : (movies.length ? <MovieList movies={movies} onEdit={()=>{}} onDelete={()=>{}} /> : <Empty />)}
    </div>
  )
}

import React, { useEffect, useState } from 'react'
import { Input, Row, Col, Spin, Empty, Pagination } from 'antd'
import { apiClient } from '../api/apiClient'
import { useAuth } from '../hooks/useAuth'
import { useNavigate } from 'react-router-dom'
import { message } from 'antd'
import SearchBar from '../components/SearchBar'
import FilterControls from '../components/FilterControls'
import MovieList from '../components/MovieList'
import MovieForm from '../components/MovieForm'
import { Movie } from '../types'

export default function Home(){
  const [q, setQ] = useState('')
  const [year, setYear] = useState<number|undefined>(undefined)
  const [type, setType] = useState<'movie'|'series'|''|undefined>('')
  const [movies, setMovies] = useState<Movie[]>([])
  const [loading, setLoading] = useState(false)

  const { isAdmin } = useAuth()
  const navigate = useNavigate()

  // load function and debounce search + client-side pagination
  const load = () => {
    setLoading(true)
    const payload = { q: q || undefined, year, type: type || undefined }
    return apiClient.getMovies(payload as any).then(list => { setMovies(list) }).finally(()=>setLoading(false))
  }

  useEffect(() => {
    let mounted = true
    setLoading(true)
    const payload = { q: q || undefined, year, type: type || undefined }
    const t = setTimeout(() => {
      apiClient.getMovies(payload as any).then(list => { if (mounted) setMovies(list) }).finally(()=>mounted && setLoading(false))
    }, 300)
    return ()=>{ mounted = false; clearTimeout(t) }
  }, [q, year, type])

  // pagination handling: slice movies for current page
  const [page, setPage] = useState(1)
  const pageSize = 8
  useEffect(()=> setPage(1), [q, year, type])
  const paginated = movies.slice((page-1)*pageSize, page*pageSize)

  const handleDelete = async (id: string) => {
    if (!isAdmin()) { message.error('僅管理員可刪除電影'); return }
    if (!confirm('確定要刪除這部電影嗎？')) return
    try{
      await apiClient.deleteMovie(id)
      message.success('已刪除')
      await load()
    }catch(e:any){ message.error(e.message || '刪除失敗') }
  }
  const handleEdit = (id: string) => {
    if (!isAdmin()) { message.info('請到管理頁面進行編輯'); navigate('/admin'); return }
    ;(async () => {
      try {
        const m = await apiClient.getMovie(id)
        setEditing(m)
        setEditVisible(true)
      } catch (e:any) { message.error('無法載入電影資料') }
    })()
  }

  const [editVisible, setEditVisible] = useState(false)
  const [editing, setEditing] = useState<Movie | null>(null)

  return (
    <div>
      <Row justify="space-between" align="middle" style={{marginBottom:16}}>
        <Col>
          <SearchBar value={q} onChange={setQ} />
        </Col>
        <Col>
          <FilterControls year={year} setYear={setYear as any} type={type as any} setType={setType as any} />
        </Col>
      </Row>
      {loading ? <Spin /> : (movies.length ? <>
        <MovieList movies={paginated} onEdit={(m)=>handleEdit(m.id)} onDelete={(m)=>handleDelete(m.id)} />
        <MovieForm open={editVisible} onClose={() => { setEditVisible(false); setEditing(null); load() }} movie={editing} />
        {movies.length > pageSize && (
          <div style={{textAlign:'center', marginTop:16}}>
            <Pagination current={page} pageSize={pageSize} total={movies.length} onChange={(p)=>setPage(p)} />
          </div>
        )}
      </> : <Empty />)}
    </div>
  )
}

import React from 'react'
import { Form, Input, Button, Card } from 'antd'
import { useAuth } from '../hooks/useAuth'
import { useNavigate } from 'react-router-dom'

export default function Register(){
  const { register, loading } = useAuth()
  const nav = useNavigate()
  const onFinish = async (vals:any) => {
    await register(vals.name, vals.email, vals.password)
    nav('/')
  }
  return (
    <div style={{display:'flex',justifyContent:'center',paddingTop:40}}>
      <Card title="Register" style={{width:360}}>
        <Form layout="vertical" onFinish={onFinish}>
          <Form.Item label="Name" name="name" rules={[{required:true, message: '請輸入姓名'}]}> <Input /> </Form.Item>
          <Form.Item label="Email" name="email" rules={[{required:true, message: '請輸入電子郵件'}, { type: 'email', message: '請輸入有效的電子郵件地址' }]}> <Input /> </Form.Item>
          <Form.Item label="Password" name="password" rules={[{required:true, message: '請輸入密碼'}, { min: 6, message: '密碼至少 6 位' }]}> <Input.Password /> </Form.Item>
          <Form.Item>
            <Button type="primary" htmlType="submit" loading={loading}>Register</Button>
          </Form.Item>
        </Form>
      </Card>
    </div>
  )
}

export type MovieType = 'movie' | 'series' | 'episode'
export interface Movie { id: string title: string year: number type: MovieType poster?: string description?: string }
export interface User { id: string name: string email: string password: string role?: 'user' | 'admin' favorites?: string[] }

import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

// https://vitejs.dev/config/
export default defineConfig({
  plugins: [react()],
})
